__kernel void dynproc_kernel(
    int iteration,
    __global int* gpuWall,
    __global int* gpuSrc,
    __global int* gpuResults,
    int cols,
    int rows,
    int startStep,
    int border,
    int HALO,
    __local int* prev,
    __local int* result,
    __global int* outputBuffer)
{
    (void)rows;
    (void)border;
    (void)HALO;
    (void)prev;
    (void)result;
    (void)outputBuffer;

    if (get_group_id(0) != 0) return;

    const int lid = (int)get_local_id(0);
    const int lsize = (int)get_local_size(0);

    __global int* src = gpuSrc;
    __global int* dst = gpuResults;

    for (int t = 0; t < iteration; t++) {
        int wallRow = (startStep + t) * cols;
        for (int n = lid; n < cols; n += lsize) {
            int m = src[n];
            if (n > 0) {
                int v = src[n - 1];
                m = (m <= v) ? m : v;
            }
            if (n < cols - 1) {
                int v = src[n + 1];
                m = (m <= v) ? m : v;
            }
            dst[n] = gpuWall[wallRow + n] + m;
        }

        barrier(CLK_GLOBAL_MEM_FENCE);

        __global int* tmp = src;
        src = dst;
        dst = tmp;
    }

    if ((iteration & 1) == 0) {
        for (int n = lid; n < cols; n += lsize) {
            gpuResults[n] = gpuSrc[n];
        }
    }
}
